import os
from flask import Flask, jsonify, request
from pymemcache.client import Client
import time
import random

# Configuration
MEMCACHED_HOST = os.environ.get('MEMCACHED_HOST', 'localhost')
MEMCACHED_PORT = int(os.environ.get('MEMCACHED_PORT', 11211))
DB_QUERY_TTL = 60  # seconds for database query cache
API_RESPONSE_TTL = 30  # seconds for API response cache

app = Flask(__name__)

# Initialize Memcached client
try:
    cache = Client((MEMCACHED_HOST, MEMCACHED_PORT))
    # Test connection
    cache.set('test_key', 'test_value', expire=1)
    if cache.get('test_key') == b'test_value':
        print(f"Successfully connected to Memcached at {MEMCACHED_HOST}:{MEMCACHED_PORT}")
    else:
        print(f"Failed to verify Memcached connection at {MEMCACHED_HOST}:{MEMCACHED_PORT}. Is it running?")
        cache = None # Disable caching if connection fails
except Exception as e:
    print(f"Error connecting to Memcached: {e}")
    cache = None # Disable caching if connection fails

# --- Simulate Database Operations ---
# In a real application, this would interact with a database
# For demonstration, we'll use a simple dictionary and simulate delay

_in_memory_db = {
    '1': {'id': '1', 'name': 'Item A', 'description': 'Description for Item A'},
    '2': {'id': '2', 'name': 'Item B', 'description': 'Description for Item B'},
    '3': {'id': '3', 'name': 'Item C', 'description': 'Description for Item C'},
}

def simulate_db_query(item_id):
    """Simulates a slow database query."""
    time.sleep(random.uniform(0.1, 0.5))  # Simulate network latency and DB processing
    return _in_memory_db.get(item_id)

def simulate_db_all_items_query():
    """Simulates a slow database query for all items."""
    time.sleep(random.uniform(0.3, 0.8))
    return list(_in_memory_db.values())

# --- Caching Decorator for Database Queries ---
def cache_db_query(key_prefix, ttl):
    def decorator(func):
        def wrapper(*args, **kwargs):
            if cache is None:
                return func(*args, **kwargs) # Skip cache if not connected

            # Create a cache key based on function name and arguments
            cache_key = f"{key_prefix}:{func.__name__}:{'-'.join(map(str, args))}"
            
            # Try to get data from cache
            cached_data = cache.get(cache_key)

            if cached_data:
                print(f"Cache HIT for DB query: {cache_key}")
                # pymemcache returns bytes, decode it
                return app.json.loads(cached_data)
            
            print(f"Cache MISS for DB query: {cache_key}. Executing actual query...")
            # Execute the actual database query
            result = func(*args, **kwargs)
            
            # Store result in cache
            if result is not None:
                cache.set(cache_key, app.json.dumps(result), expire=ttl)
            return result
        return wrapper
    return decorator

# Cached DB functions
@cache_db_query("db_item", DB_QUERY_TTL)
def get_item_from_db(item_id):
    return simulate_db_query(item_id)

@cache_db_query("db_all_items", DB_QUERY_TTL)
def get_all_items_from_db():
    return simulate_db_all_items_query()

