@app.route('/items/<item_id>')
def get_item(item_id):
    # API response caching mechanism (manual for demonstration, could be a decorator)
    api_cache_key = f"api:item:{item_id}"

    if cache:
        cached_api_response = cache.get(api_cache_key)
        if cached_api_response:
            print(f"API Cache HIT for {api_cache_key}")
            return app.json.loads(cached_api_response)

    print(f"API Cache MISS for {api_cache_key}. Fetching from DB...")
    
    item = get_item_from_db(item_id)
    if item:
        response_data = jsonify(item)
        if cache:
            cache.set(api_cache_key, app.json.dumps(item), expire=API_RESPONSE_TTL)
        return response_data
    return jsonify({'error': 'Item not found'}), 404

@app.route('/items')
def get_all_items():
    # API response caching mechanism
    api_cache_key = "api:all_items"

    if cache:
        cached_api_response = cache.get(api_cache_key)
        if cached_api_response:
            print(f"API Cache HIT for {api_cache_key}")
