@app.route('/clear_cache/<key_type>', methods=['POST'])
def clear_cache(key_type):
    if not cache:
        return jsonify({"message": "Memcached is not connected"}), 500

    if key_type == 'db_item':
        # In a real app, you might invalidate specific keys or use a more robust cache invalidation strategy
        # For simplicity, we'll just demonstrate clearing for this example
        item_id = request.args.get('id')
        if item_id:
            db_cache_key = f"db_item:get_item_from_db:{item_id}"
            api_cache_key = f"api:item:{item_id}"
            cache.delete(db_cache_key)
            cache.delete(api_cache_key)
            return jsonify({"message": f"Cache cleared for item {item_id}"})
        else:
            return jsonify({"message": "Please provide an 'id' parameter for db_item clear"}), 400
    elif key_type == 'db_all_items':
        cache.delete("db_all_items:get_all_items_from_db:")
        cache.delete("api:all_items")
        return jsonify({"message": "Cache cleared for all items (DB and API)"})
    elif key_type == 'all':
        # WARNING: This flushes the entire cache. Use with extreme caution in production.
        cache.flush_all()
        return jsonify({"message": "ALL cache flushed (DANGEROUS IN PRODUCTION!)"})
    else:
        return jsonify({"message": "Invalid key_type. Use 'db_item', 'db_all_items', or 'all'"}), 400

